import { createClient } from '@supabase/supabase-js'
import { NextResponse } from 'next/server'
export const dynamic = 'force-dynamic'
export const maxDuration = 60

const IMAGES: Record<string,string> = {
  'refri': ``,
  'suco': ``,
  'dogao_completo': ``,
  'xtudo': ``,
  'batata_cheddar': ``,
  'xburger': ``,
  'onion': ``,
  'xsalada': ``,
  'xbacon': ``,
  'combo_solo': ``,
  'batata': ``,
  'combo_casal': ``,
  'dogao_simples': ``,
  'dogao_especial': ``,
  'milkshake': ``,
  'agua': ``,
  'dogao_frango': ``,
  'brownie': ``,
  'dogao_calabresa': ``
}
const NAME_TO_FILE: Record<string,string> = {"Dogão Simples": "dogao_simples", "Dogão Completo": "dogao_completo", "Dogão Especial do Denis": "dogao_especial", "Dogão Calabresa": "dogao_calabresa", "Dogão Frango c/ Catupiry": "dogao_frango", "X-Burger": "xburger", "X-Salada": "xsalada", "X-Bacon": "xbacon", "X-Tudo do Denis": "xtudo", "Batata Frita": "batata", "Batata c/ Cheddar e Bacon": "batata_cheddar", "Onion Rings": "onion", "Refrigerante Lata": "refri", "Suco Natural": "suco", "Água Mineral": "agua", "Brownie com Sorvete": "brownie", "Milkshake": "milkshake", "Combo Casal": "combo_casal", "Combo Solo": "combo_solo"}

export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!)
  const slug = 'dogao-do-denis-ikir'
  const { data: biz } = await supabase.from('businesses').select('id').eq('slug', slug).single()
  if (!biz) return NextResponse.json({ error: 'business not found' }, { status: 404 })

  await supabase.storage.createBucket('menu', { public: true }).catch(()=>{})
  const fileUrl: Record<string,string> = {}
  for (const f of Object.keys(IMAGES)) {
    const buffer = Buffer.from(IMAGES[f], 'base64')
    const path = `${biz.id}/real_${f}.jpg`
    await supabase.storage.from('menu').upload(path, buffer, { contentType: 'image/jpeg', upsert: true })
    fileUrl[f] = supabase.storage.from('menu').getPublicUrl(path).data.publicUrl
  }

  let updated = 0, missing: string[] = []
  for (const [name, file] of Object.entries(NAME_TO_FILE)) {
    const { data, error } = await supabase.from('products').update({ image_url: fileUrl[file] })
      .eq('business_id', biz.id).eq('name', name).select('id')
    if (!error && data && data.length) updated += data.length
    else missing.push(name)
  }
  return NextResponse.json({ ok: true, updated, missing, slug })
}
